def total_due(items, tax_rate):
    subtotal = sum(item["price"] * item["quantity"] for item in items)

    if subtotal > 100:
        total = sum(
            item["price"] * item["quantity"] * (1 if item.get("category") == "gift_card" else 0.9)
            for item in items
        )
    else:
        total = subtotal

    return round(total * (1 + tax_rate), 2)
